func AllSources() []Source {
	sources := BuiltInAppIDSources()
	sources = append(sources, BuiltInRelaySources()...)
	sources = append(sources, ThirdPartySources()...)
	return sources
}

func FindSource(sourceType AuthSourceType, provider AuthProvider, appID string) (Source, bool) {
	switch sourceType {
	case SourceTypeBuiltInAppID:
		source, ok := builtInAppIDByID[appID]
		if !ok || provider != "" && source.Provider != provider {
			return Source{}, false
		}
		return source, true
	case SourceTypeBuiltInRelay:
		for _, source := range BuiltInRelaySources() {
			if (provider == "" || source.Provider == provider) && (appID == "" || source.AppID == appID) {
				return source, true
			}
		}
	case SourceTypeThirdPartyService:
		for _, source := range ThirdPartySources() {
			if (provider == "" || source.Provider == provider) && (appID == "" || source.AppID == appID) {
				return source, true
			}
		}
	}
	return Source{}, false
}

func SourceFromCreateRequest(sourceType AuthSourceType, provider AuthProvider, appID string, selectedApp string, customAppName string) (Source, error) {
	if sourceType == "" {
		return sourceFromLegacyCreateRequest(appID, selectedApp, customAppName)
	}
	switch sourceType {
	case SourceTypeBuiltInAppID:
		source, ok := FindSource(SourceTypeBuiltInAppID, ProviderOfficialPKCE, strings.TrimSpace(appID))
		if !ok {
			return Source{}, fmt.Errorf("不支持的内置 115 APPID")
		}
		return source, nil
	case SourceTypeBuiltInRelay:
		return relaySourceFromProvider(provider, selectedApp)
	case SourceTypeThirdPartyService:
		source, ok := FindSource(SourceTypeThirdPartyService, provider, strings.TrimSpace(appID))
		if !ok {
			return Source{}, fmt.Errorf("不支持的第三方 115 授权服务")
		}
		return source, nil
	case SourceTypeCustomAppID:
		appID = strings.TrimSpace(appID)
		if appID == "" {
			return Source{}, fmt.Errorf("自定义应用ID不能为空")
		}
		name := strings.TrimSpace(customAppName)
		if name == "" {
			name = CustomAppName
		}
		return Source{SourceType: SourceTypeCustomAppID, Provider: ProviderOfficialPKCE, AppID: appID, AppName: name, DisplayName: name}, nil
	default:
		return Source{}, fmt.Errorf("不支持的115授权来源")
	}
}

func (source Source) StorageAppID() string {
	return source.AppID
}

func (source Source) StorageAppName() string {
	return source.AppName
}

func SearchBuiltInAppIDSources(keyword string, offset int, limit int) AppIDSearchResult {
	keyword = strings.ToLower(strings.TrimSpace(keyword))
	if offset < 0 {
		offset = 0
	}
	if limit <= 0 {
		limit = 50
	}
	if limit > 100 {
		limit = 100
	}
	matched := make([]Source, 0, len(builtInAppIDCatalog))
	for _, source := range builtInAppIDCatalog {
		if keyword != "" && !strings.Contains(strings.ToLower(source.AppID), keyword) && !strings.Contains(strings.ToLower(source.AppName), keyword) {
			continue
		}
		matched = append(matched, source)
	}
	total := len(matched)
	if offset > total {
		offset = total
	}
	end := offset + limit
	if end > total {
		end = total
	}
	items := append([]Source(nil), matched[offset:end]...)
	return AppIDSearchResult{Items: items, Total: total, Offset: offset, Limit: limit}
}

func ResolveAccountSource(appID string, appIDName string) Source {
	switch appID {
	case BuiltInRelayQMediaSync:
		return Source{SourceType: SourceTypeBuiltInRelay, Provider: ProviderQMediaSync, AppID: appID, AppName: appID, DisplayName: appID, RequiresEncryptionKey: true}
	case BuiltInRelayQ115STRM, BuiltInRelayMQMediaLibrary:
		return Source{SourceType: SourceTypeBuiltInRelay, Provider: ProviderMQFamily, AppID: appID, AppName: appID, DisplayName: appID, RequiresEncryptionKey: true}
	}
	if source, ok := FindSource(SourceTypeBuiltInAppID, ProviderOfficialPKCE, appID); ok {
		return source
	}
	if source, ok := FindSource(SourceTypeThirdPartyService, "", appID); ok {
		return source
	}
	name := strings.TrimSpace(appIDName)
	if name == "" {
		name = CustomAppName
	}
	return Source{SourceType: SourceTypeCustomAppID, Provider: ProviderOfficialPKCE, AppID: appID, AppName: name, DisplayName: name}
}

func sourceFromLegacyCreateRequest(appID string, selectedApp string, customAppName string) (Source, error) {
	selectedApp = strings.TrimSpace(selectedApp)
	switch selectedApp {
	case BuiltInRelayQMediaSync:
		return relaySourceFromProvider(ProviderQMediaSync, selectedApp)
	case BuiltInRelayQ115STRM, BuiltInRelayMQMediaLibrary:
		return relaySourceFromProvider(ProviderMQFamily, selectedApp)
	case "自定义", CustomAppName:
		appID = strings.TrimSpace(appID)
		if appID == "" {
			return Source{}, fmt.Errorf("自定义应用ID不能为空")
		}
		name := strings.TrimSpace(customAppName)
		if name == "" {
			name = CustomAppName
		}
		return Source{SourceType: SourceTypeCustomAppID, Provider: ProviderOfficialPKCE, AppID: appID, AppName: name, DisplayName: name}, nil
	default:
		return Source{}, fmt.Errorf("不支持的115开放平台应用")
	}
}

func relaySourceFromProvider(provider AuthProvider, selectedApp string) (Source, error) {
	selectedApp = strings.TrimSpace(selectedApp)
	for _, source := range BuiltInRelaySources() {
		if provider != "" && source.Provider != provider {
			continue
		}
		if selectedApp != "" && source.AppID != selectedApp && source.AppName != selectedApp {
			continue
		}
		return source, nil
	}
	return Source{}, fmt.Errorf("不支持的115内置中转")
}
